let running = false; let timer = null; let count = 0;
let dataPoints = [];
const MAX_POINTS = 100;
const sdk = window.CueStack;

// Setup chart canvas
const canvas = document.createElement('canvas');
document.getElementById('chartArea').appendChild(canvas);

function drawChart() {
  const w = canvas.parentElement.clientWidth;
  const h = canvas.parentElement.clientHeight;
  canvas.width = w; canvas.height = h;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = '#1e1e1e'; ctx.fillRect(0, 0, w, h);
  if (dataPoints.length < 2) { requestAnimationFrame(drawChart); return; }
  // Temperature (red)
  const temps = dataPoints.map(function(d) { return d.temperature; });
  const minT = Math.min.apply(null, temps) - 1;
  const maxT = Math.max.apply(null, temps) + 1;
  ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2; ctx.beginPath();
  dataPoints.forEach(function(d, i) {
    var x = (i / (MAX_POINTS - 1)) * w;
    var y = h - ((d.temperature - minT) / (maxT - minT)) * h;
    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
  }); ctx.stroke();
  // Humidity (blue)
  var humids = dataPoints.map(function(d) { return d.humidity; });
  var minH = Math.min.apply(null, humids) - 1;
  var maxH = Math.max.apply(null, humids) + 1;
  ctx.strokeStyle = '#3b82f6'; ctx.beginPath();
  dataPoints.forEach(function(d, i) {
    var x = (i / (MAX_POINTS - 1)) * w;
    var y = h - ((d.humidity - minH) / (maxH - minH)) * h;
    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
  }); ctx.stroke();
  ctx.fillStyle = '#ef4444'; ctx.font = '11px monospace';
  ctx.fillText('Temp: ' + temps[temps.length-1].toFixed(1) + '°C', 8, 14);
  ctx.fillStyle = '#3b82f6';
  ctx.fillText('Humid: ' + humids[humids.length-1].toFixed(1) + '%', 8, 28);
  requestAnimationFrame(drawChart);
}
requestAnimationFrame(drawChart);

function toggleSimulation() {
  running = !running;
  var btn = document.getElementById('toggleBtn');
  var status = document.getElementById('status');
  if (running) {
    btn.textContent = 'Stop Simulation'; btn.className = 'running';
    status.textContent = 'Running'; status.style.background = '#f0fde8'; status.style.color = '#15803d';
    startSending();
  } else {
    btn.textContent = 'Start Simulation'; btn.className = '';
    status.textContent = 'Stopped'; status.style.background = '#fef2f2'; status.style.color = '#dc2626';
    clearInterval(timer);
  }
}

function startSending() {
  clearInterval(timer);
  timer = setInterval(sendSample, parseInt(document.getElementById('rate').value));
}

function sendSample() {
  var channel = document.getElementById('channel').value;
  var meanT = parseFloat(document.getElementById('meanTemp').value);
  var meanH = parseFloat(document.getElementById('meanHumid').value);
  var noise = parseFloat(document.getElementById('noise').value);
  var freq = parseFloat(document.getElementById('freq').value);
  var t = count * (parseInt(document.getElementById('rate').value) / 1000);
  var temp = meanT + noise * (Math.random() - 0.5) * 2 + Math.sin(2 * Math.PI * freq * t);
  var humid = meanH + noise * (Math.random() - 0.5) * 2 + Math.cos(2 * Math.PI * freq * t) * 0.5;
  var payload = { temperature: +temp.toFixed(2), humidity: +humid.toFixed(2), t: t };
  sdk.publish(channel, payload);
  dataPoints.push(payload);
  if (dataPoints.length > MAX_POINTS) dataPoints.shift();
  document.getElementById('liveTemp').textContent = payload.temperature.toFixed(1) + '°C';
  document.getElementById('liveHumid').textContent = payload.humidity.toFixed(1) + '%';
  count++;
  document.getElementById('counter').textContent = count + ' samples sent';
  var log = document.getElementById('log');
  log.innerHTML = '<div>[' + new Date().toLocaleTimeString() + '] ' + channel + ': T=' + payload.temperature + '°C H=' + payload.humidity + '%</div>' + log.innerHTML;
  if (log.children.length > 50) log.lastChild.remove();
}

['meanTemp','meanHumid','noise','freq'].forEach(function(id) {
  var el = document.getElementById(id);
  var val = document.getElementById(id + 'Val');
  el.oninput = function() {
    var suffix = id === 'meanTemp' ? '°C' : id === 'meanHumid' ? '%' : id === 'freq' ? ' Hz' : '';
    val.textContent = el.value + suffix;
  };
});
